('nigerian_professional', 'NIQS Probationary Exam', 'Measurement', 'What is the correct order of stages in taking-off?', 'mcq', '["Preliminaries, Dimension Sheet, Abstract, Bill", "Dimension Sheet, Preliminaries, Abstract, Bill", "Preliminaries, Abstract, Dimension Sheet, Bill", "Abstract, Dimension Sheet, Preliminaries, Bill"]'::jsonb, 'A', 'The correct sequence is: Preliminaries, Dimension Sheet, Abstract, and Bill of Quantities.', 'medium', 2023),
('nigerian_professional', 'NIQS Probationary Exam', 'Measurement', 'Which document provides the rules for expressing dimensions in bills of quantities?', 'mcq', '["SMM7", "NRM1", "CESMM4", "POMI"]'::jsonb, 'A', 'SMM7 provides the rules for expressing and formatting dimensions.', 'easy', 2021),
('nigerian_professional', 'NIQS Probationary Exam', 'Measurement', 'In SMM7, the minimum dimension for wall thickness is:', 'mcq', '["50mm", "75mm", "100mm", "115mm"]'::jsonb, 'B', 'The minimum dimension for wall thickness under SMM7 is 75mm.', 'hard', 2022),
('nigerian_professional', 'NIQS Probationary Exam', 'Measurement', 'What does the term deduction mean in taking-off?', 'mcq', '["Adding dimensions together", "Subtracting openings from solid quantities", "Multiplying dimensions", "Dividing quantities"]'::jsonb, 'B', 'Deductions involve subtracting openings or voids from solid quantities.', 'easy', 2020),
