('nigerian_professional', 'NIQS Probationary Exam', 'Measurement', 'Which item is measured in linear metres under SMM7?', 'mcq', '["Floor finishes", "Skirting boards", "Wall tiling", "Ceiling finishes"]'::jsonb, 'B', 'Skirting boards are measured in linear metres under SMM7.', 'easy', 2021),
('nigerian_professional', 'NIQS Probationary Exam', 'Measurement', 'In SMM7, excavations are measured from:', 'mcq', '["Top of ground to underside of foundations", "Underside of foundations to bottom of excavation", "Ground level to finished floor level", "From any point as convenient"]'::jsonb, 'B', 'Excavations are measured from the underside of foundations to the bottom.', 'medium', 2020),
('nigerian_professional', 'NIQS Probationary Exam', 'Measurement', 'In SMM7, which items are measured in numbers?', 'mcq', '["Doors and windows", "Floor tiles", "Wall finishes", "Ceiling boards"]'::jsonb, 'A', 'Doors and windows are measured in numbers under SMM7.', 'easy', 2022),
('nigerian_professional', 'NIQS Probationary Exam', 'Cost Planning', 'What is the primary purpose of an elemental cost plan?', 'mcq', '["To set the final contract sum", "To establish and control the budget", "To price the bill of quantities", "To settle final account disputes"]'::jsonb, 'B', 'The primary purpose is to establish and control the project budget.', 'easy', 2023),
