('nigerian_professional', 'NIQS Probationary Exam', 'Cost Planning', 'Which element typically accounts for the highest percentage of building cost?', 'mcq', '["Substructure", "Superstructure", "Finishes", "Services"]'::jsonb, 'B', 'The superstructure typically accounts for 40-50% of total cost.', 'medium', 2022),
('nigerian_professional', 'NIQS Probationary Exam', 'Cost Planning', 'What is value engineering in cost planning?', 'mcq', '["Reducing quality to cut costs", "Optimising the cost-to-value relationship", "Eliminating all contingencies", "Using cheaper contractors"]'::jsonb, 'B', 'Value engineering seeks the best value for money.', 'medium', 2023),
