('nigerian_professional', 'NIQS Probationary Exam', 'BOQ', 'What is a provisional sum in a BOQ?', 'mcq', '["A fixed price for defined work", "An estimate for work not yet defined", "A sum for contingencies only", "A daywork rate"]'::jsonb, 'B', 'A provisional sum is an estimate for work not yet fully defined.', 'medium', 2023),
